module up_counter_2bit(
    input clk,
    input enable,
    input reset,
    output reg [1:0] count
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
    begin
        if (reset)
            count <= 2'b00;
        else if (enable)
            count <= count + 1;
    end

endmodule
